// The pharmacogenomics (PGx) gene–drug guidance dataset, loaded onto the curated-
// dataset framework (issue #860 Track B, wave 2). Copies the mets.ts / icd10-common.ts
// shape: import the envelope JSON (generated by scripts/gen-pgx.ts), validate it once
// with loadDataset(), and expose the guidance ENTRIES + the drug vocabulary + the
// star-allele function table (in `meta`) the cross-check consumes. Identity is the
// ordered [gene, drug, status] COMPOSITE (compositeStrategy) — the framework's
// composite-key machinery. The registry lists this for the linter; lib/pgx.ts is the
// DOMAIN cross-check. Pure — no DB, no network.

import rawPgx from "./data/pgx.json";
import { loadDataset } from "./loader";
import { compositeStrategy } from "./matcher";
import type {
  GuidanceEntry,
  PgxMeta,
  RawAllele,
  RawDrug,
} from "@/scripts/gen-pgx";

export type {
  GuidanceEntry,
  PgxMeta,
  RawAllele,
  RawDrug,
  Phenotype,
  PgxSeverity,
  AlleleFunction,
} from "@/scripts/gen-pgx";

// The validated dataset (envelope + guarantees). Throws at module load if the
// committed JSON ever violates the contract — a loud, early failure.
export const pgxDataset = loadDataset<GuidanceEntry, PgxMeta>(rawPgx);

// Identity strategy: the ordered [gene, drug, status] composite. For the linter.
export const pgxGuidanceStrategy = compositeStrategy("combo");

// The drug vocabulary + allele-function table (dataset meta) and the guidance rows
// (entries) the cross-check consumes.
export const PGX_DRUGS: RawDrug[] = (pgxDataset.meta as PgxMeta).drugs;
export const PGX_ALLELES: RawAllele[] = (pgxDataset.meta as PgxMeta).alleles;
export const PGX_GUIDANCE: GuidanceEntry[] = pgxDataset.entries;
